import{_ as t,o,c as d,a2 as i}from"./chunks/framework.BZO4qERu.js";const u=JSON.parse('{"title":"PaperSeek 在线体验版使用说明","description":"","frontmatter":{},"headers":[],"relativePath":"online-demo.md","filePath":"online-demo.md","lastUpdated":1780734811000}'),a={name:"online-demo.md"};function r(l,e,n,s,c,p){return o(),d("div",null,[...e[0]||(e[0]=[i('<h1 id="paperseek-在线体验版使用说明" tabindex="-1">PaperSeek 在线体验版使用说明 <a class="header-anchor" href="#paperseek-在线体验版使用说明" aria-label="Permalink to &quot;PaperSeek 在线体验版使用说明&quot;">​</a></h1><p>PaperSeek 在线体验版用于快速试用完整 Web UI，不需要自己部署服务，也不需要准备 OpenAlex Key。页面支持 <code>EN</code> / <code>中文</code> 语言切换，选择会保存在当前浏览器。</p><p>在线体验：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.paperseek.xyz/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="两种使用模式" tabindex="-1">两种使用模式 <a class="header-anchor" href="#两种使用模式" aria-label="Permalink to &quot;两种使用模式&quot;">​</a></h2><p>在线体验版的配置区提供两种模型调用方式。</p><h3 id="use-modelscope-service" tabindex="-1">Use ModelScope service <a class="header-anchor" href="#use-modelscope-service" aria-label="Permalink to &quot;Use ModelScope service&quot;">​</a></h3><p><code>Use ModelScope service</code> 使用 ModelScope API-Inference。这个模式需要点击右上角或配置区中的登录按钮，并使用 ModelScope 账号授权登录。登录后：</p><ul><li>PaperSeek 使用登录用户授权的 ModelScope API-Inference token 调用模型。</li><li>模型调用消耗登录用户自己的 ModelScope API-Inference 免费额度。</li><li>PaperSeek 不会把 ModelScope API-Inference token 保存到数据库；token 只随当前登录会话用于发起模型请求。</li><li>数据源默认使用站点服务端 OpenAlex key 池，OpenAlex 引用扩展默认开启。</li><li><code>History</code> 页面会显示当前登录账号的云端历史记录。</li></ul><p>ModelScope 模型路由默认是 <code>Automatic</code>。自动模式会在一组已测试的 API-Inference 模型之间尝试可用模型，不在前端展示具体轮询顺序。也可以选择 <code>Custom model</code> 并填写自定义 ModelScope model ID。</p><h3 id="use-your-own-api" tabindex="-1">Use your own API <a class="header-anchor" href="#use-your-own-api" aria-label="Permalink to &quot;Use your own API&quot;">​</a></h3><p><code>Use your own API</code> 适合已经有模型服务 API Key 的用户。这个模式不要求登录：</p><ul><li>默认 provider 是 <code>OpenAI</code>。</li><li>API Key、Base URL、模型和运行参数只用于当前浏览器会话。</li><li>如果 provider 选择 <code>Ollama</code>，API Key 可留空，用于本地兼容端点。</li><li>ModelScope API-Inference 也可以作为自带 API 的 provider 使用，但不作为默认选项。</li><li>PaperSeek 仍默认使用站点 OpenAlex key 池；只有在高级设置中填写自己的 OpenAlex Key 或其它数据源 Key 时才会覆盖。</li><li>未登录时不能使用托管服务的云端历史记录。</li></ul><h2 id="推荐流程" tabindex="-1">推荐流程 <a class="header-anchor" href="#推荐流程" aria-label="Permalink to &quot;推荐流程&quot;">​</a></h2><ol><li>进入 <a href="https://www.paperseek.xyz/" target="_blank" rel="noreferrer">paperseek.xyz</a>。</li><li>如需中文界面，点击顶部状态条中的 <code>中文</code>。</li><li>选择模型模式： <ul><li>想使用 ModelScope 免费 API-Inference 额度：选择 <code>Use ModelScope service</code> 并登录。</li><li>想使用自己的模型服务：选择 <code>Use your own API</code>，填写 API Key。</li></ul></li><li>输入研究问题。</li><li>如需限定学科范围，打开 <code>Discipline Fields</code> 并勾选一个或多个学科；不勾选时表示 <code>Any field</code>。</li><li>保持默认 OpenAlex 数据源，或在配置区切换到 Crossref；自带 API 模式的高级设置中还可配置 Web of Science Starter。</li><li>点击 <code>Check Config</code> 检查配置。失败时页面会弹出问题列表，并提示需要修复的字段。</li><li>点击 <code>Run Search</code> 开始检索。</li><li>在 <code>Results</code> 查看、筛选和勾选论文，并导出 CSV。</li><li>在 <code>Citation Map</code> 查看 OpenAlex 引用扩展形成的引用关系图。</li><li>登录用户可在 <code>History</code> 回看云端历史检索记录。</li></ol><h2 id="discipline-fields" tabindex="-1">Discipline Fields <a class="header-anchor" href="#discipline-fields" aria-label="Permalink to &quot;Discipline Fields&quot;">​</a></h2><p>在线体验版与开源自托管版使用同一套 Discipline Fields 选择器。它基于 OpenAlex Field 学科分类，支持一次选择多个领域，例如 <code>Computer Science</code>、<code>Business, Management and Accounting</code> 或 <code>Social Sciences</code>。</p><p>不同数据源的处理方式不同：</p><table tabindex="0"><thead><tr><th>数据源</th><th>在线版处理方式</th></tr></thead><tbody><tr><td>OpenAlex</td><td>应用 <code>primary_topic.field.id</code> 原生过滤，并把所选学科传给引用扩展。</td></tr><tr><td>Web of Science Starter</td><td>映射为 Web of Science Categories 的 <code>WC=</code> 限制。</td></tr><tr><td>Crossref</td><td>Crossref 没有同一套学科 taxonomy，PaperSeek 会把所选学科作为查询上下文。</td></tr></tbody></table><p><code>Discipline Fields</code> 与高级设置中的 <code>Field Hint</code> 不同。<code>Field Hint</code> 是自由文本提示，用来帮助 LLM 生成更贴近领域的检索式；<code>Discipline Fields</code> 是结构化学科限制，更适合在结果过宽时收窄候选池。</p><h2 id="账号与权限" tabindex="-1">账号与权限 <a class="header-anchor" href="#账号与权限" aria-label="Permalink to &quot;账号与权限&quot;">​</a></h2><p>在线体验版不强制所有用户登录。登录与未登录的主要差异是：</p><table tabindex="0"><thead><tr><th>功能</th><th>未登录</th><th>已登录 ModelScope</th></tr></thead><tbody><tr><td>使用自己的模型 API</td><td>支持</td><td>支持</td></tr><tr><td>使用站点 OpenAlex key 池</td><td>支持</td><td>支持</td></tr><tr><td>使用 Discipline Fields</td><td>支持</td><td>支持</td></tr><tr><td>使用 ModelScope service</td><td>不支持</td><td>支持，使用登录账号 API-Inference 额度</td></tr><tr><td>云端 History</td><td>不支持</td><td>支持，按登录账号隔离</td></tr></tbody></table><p>公共电脑或共享浏览器使用后请退出登录。历史记录按登录账号隔离，不按 IP 地址隔离。</p><h2 id="使用前检查" tabindex="-1">使用前检查 <a class="header-anchor" href="#使用前检查" aria-label="Permalink to &quot;使用前检查&quot;">​</a></h2><p>使用 <code>Use ModelScope service</code> 前，请确认：</p><ul><li>ModelScope 账号已经绑定阿里云账号。</li><li>绑定的阿里云账号已完成实名认证。</li><li>如果使用 RAM 账号，需要按官方教程完成对应的绑定与授权。</li><li>授权登录 PaperSeek 时允许 <code>api-inference</code> 范围，否则无法代表当前用户调用模型。</li></ul><p>如果登录成功但模型调用失败，请先检查 ModelScope 账号的阿里云绑定、实名认证和授权状态。完成绑定或授权后，建议退出 PaperSeek 并重新登录一次。</p><p>ModelScope API-Inference 的官方限制请以文档为准：</p><ul><li><a href="https://modelscope.cn/docs/model-service/API-Inference/limits" target="_blank" rel="noreferrer">API-Inference 使用限制</a></li><li><a href="https://modelscope.cn/docs/accounts/aliyun-binding-and-authorization" target="_blank" rel="noreferrer">阿里云账号绑定与授权教程</a></li></ul><h2 id="api-inference-稳定性与额度" tabindex="-1">API-Inference 稳定性与额度 <a class="header-anchor" href="#api-inference-稳定性与额度" aria-label="Permalink to &quot;API-Inference 稳定性与额度&quot;">​</a></h2><p>ModelScope API-Inference 不是商业 SLA 服务，而是面向开发者的免费体验能力。它可能受到用户总额度、单模型额度、动态并发限制和平台资源压力影响：</p><ul><li>每位 ModelScope 注册用户当前每天有一个总调用额度，官方文档示例为所有模型合计每天 2000 次。</li><li>每个模型还有独立的单模型每日额度，额度会随资源和使用情况动态调整，最高不超过 200 次，也可能远低于 200 次。</li><li>如果某个模型返回空响应、<code>429</code> 或额度不足，在线版会尽量通过自动路由尝试其它可用模型；仍失败时可稍后重试，或改用 <code>Use your own API</code>。</li><li>平台会根据实时资源压力动态调整并发和速率限制，在线体验版更适合单人、低并发、轻量检索。</li><li>较早模型可能会逐步降低额度或下架，模型列表和可用额度以 ModelScope 实际页面和接口返回为准。</li></ul><p>PaperSeek 会读取 ModelScope 响应头中的额度信息，并在日志里显示用户总额度和当前模型额度的剩余情况。ModelScope 文档列出的相关响应头包括：</p><table tabindex="0"><thead><tr><th>响应头</th><th>含义</th></tr></thead><tbody><tr><td><code>modelscope-ratelimit-requests-limit</code></td><td>用户当天总额度</td></tr><tr><td><code>modelscope-ratelimit-requests-remaining</code></td><td>用户当天剩余额度</td></tr><tr><td><code>modelscope-ratelimit-model-requests-limit</code></td><td>当前模型当天额度</td></tr><tr><td><code>modelscope-ratelimit-model-requests-remaining</code></td><td>当前模型当天剩余额度</td></tr></tbody></table><h2 id="历史记录" tabindex="-1">历史记录 <a class="header-anchor" href="#历史记录" aria-label="Permalink to &quot;历史记录&quot;">​</a></h2><p>在线体验版会保存已登录账号的检索历史，包括：</p><ul><li>检索问题和运行配置。</li><li>工作流日志。</li><li>数据源返回的候选论文。</li><li>最终排序结果。</li></ul><p>历史记录按登录账号隔离。不同浏览器、不同设备或不同网络环境中，只要登录的是同一个账号，就能看到同一账号的历史记录；不同账号之间不会共享历史记录。未登录用户可以运行检索，但不能使用云端历史记录。</p><h2 id="与开源自托管版的区别" tabindex="-1">与开源自托管版的区别 <a class="header-anchor" href="#与开源自托管版的区别" aria-label="Permalink to &quot;与开源自托管版的区别&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>在线体验版</th><th>开源自托管版</th></tr></thead><tbody><tr><td>登录</td><td>使用自己的 API 时不需要登录；ModelScope service 和 History 需要登录</td><td>默认不需要登录</td></tr><tr><td>模型调用</td><td>可使用登录用户的 ModelScope API-Inference 额度，或填写自己的模型 API</td><td>使用你自己配置的 LLM API Key</td></tr><tr><td>OpenAlex Key</td><td>默认使用站点服务端 key 池，可在高级设置中覆盖</td><td>可匿名访问或自己配置 key</td></tr><tr><td>Discipline Fields</td><td>页面选择，随本次搜索提交</td><td>页面选择、CLI 参数或 <code>DISCIPLINE_FIELDS</code> 环境变量</td></tr><tr><td>历史记录</td><td>登录后保存到托管服务数据库</td><td>默认保存到本地 SQLite</td></tr><tr><td>适用场景</td><td>快速体验、轻量检索、临时试用</td><td>私有部署、长期使用、可控配置</td></tr></tbody></table><h2 id="隐私提示" tabindex="-1">隐私提示 <a class="header-anchor" href="#隐私提示" aria-label="Permalink to &quot;隐私提示&quot;">​</a></h2><p>不要在研究问题中输入不应上传到第三方模型服务的敏感内容。在线体验版会把检索问题、候选论文元数据和排序提示发送给所选模型服务，以完成检索式生成和结果排序。</p><p>如果需要长期使用、私有部署、稳定额度或完全控制 API Key 与数据存储，请使用开源自托管版本，并配置自己的模型服务和数据源。</p><h2 id="english" tabindex="-1">English <a class="header-anchor" href="#english" aria-label="Permalink to &quot;English&quot;">​</a></h2><p>The hosted PaperSeek demo lets you try the full Web UI without deploying your own server or preparing an OpenAlex key. The UI can switch between <code>EN</code> and <code>中文</code>, and the choice is saved in the current browser.</p><p>URL:</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://www.paperseek.xyz/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>The hosted configuration panel has two model modes:</p><ul><li><code>Use ModelScope service</code>: requires ModelScope sign-in. Model calls use the signed-in user&#39;s API-Inference quota, OpenAlex uses the hosted site key pool by default, and hosted history is available for the signed-in account. Model routing defaults to <code>Automatic</code>, which tries a tested pool of API-Inference models; advanced users can provide a custom ModelScope model ID.</li><li><code>Use your own API</code>: does not require sign-in. The default provider is OpenAI, and API key, base URL, model, and run settings are used only for the current browser session. The site OpenAlex key pool is still used unless you override source credentials in Advanced settings.</li></ul><p>Both modes support the same <code>Discipline Fields</code> picker as the open-source Web UI. Leave it at <code>Any field</code> for broad discovery, or select one or more OpenAlex Field disciplines to narrow the run. OpenAlex applies native <code>primary_topic.field.id</code> filters, WoS Starter maps selections to <code>WC=</code> categories, and Crossref uses the selected disciplines as query context.</p><p>Signing in only affects the ModelScope service mode and hosted history. Users who provide their own model API key can run searches without signing in, but they will not have hosted history.</p><p>Before using API-Inference, make sure the ModelScope account is linked to an Alibaba Cloud account, has completed real-name verification, and has granted the <code>api-inference</code> OAuth scope. For RAM accounts, follow the official binding and authorization guide.</p><p>Official ModelScope references:</p><ul><li><a href="https://modelscope.cn/docs/model-service/API-Inference/limits" target="_blank" rel="noreferrer">API Inference usage limits</a></li><li><a href="https://modelscope.cn/docs/accounts/aliyun-binding-and-authorization" target="_blank" rel="noreferrer">Alibaba Cloud account binding and authorization</a></li></ul><p>ModelScope API-Inference is a free developer-oriented service rather than a production SLA service. It is subject to a daily per-user quota, separate per-model quotas, transient empty responses, and dynamic rate limits. If automatic routing cannot complete a request, retry later or use your own model API.</p><p>PaperSeek reads ModelScope quota headers when available and shows remaining user/model quota in the run log. History is isolated by the authenticated account, not by IP address. Sign out after using PaperSeek on a shared computer. For private deployment, long-term use, or full control over API keys and storage, use the open-source self-hosted version instead.</p>',57)])])}const m=t(a,[["render",r]]);export{u as __pageData,m as default};
